namespace optiling {

// UB model for this kernel:
//   xLine: 1 * tileW
//   yLine: 1 * tileW
// Total floats = 2 * tileW => bytes = 8 * tileW
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core share
static constexpr uint32_t ALIGN_ELEMS = 256;             // align DMA size
static constexpr uint32_t HARD_CAP_ELEMS = 16384;        // avoid too-large per-iter latency

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint64_t a, uint64_t b)
{
    return static_cast<uint32_t>((a + b - 1u) / b);
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed3dAsymmetricInputSquareKernelCustomTilingData tiling;

    const gert::Shape *xShape = context->GetInputShape(0);
    const gert::Shape *wShape = context->GetInputShape(1);
    if (xShape->GetOriginShape().GetDimNum() != 5 || wShape->GetOriginShape().GetDimNum() != 5) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N  = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(0));
    const uint32_t Cin= static_cast<uint32_t>(xShape->GetOriginShape().GetDim(1));
    const uint32_t D  = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(2));
    const uint32_t H  = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(3));
    const uint32_t W  = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(4));

    // PyTorch conv_transpose3d weight: [Cin, Cout, kD, kH, kW]
    const uint32_t CinW= static_cast<uint32_t>(wShape->GetOriginShape().GetDim(0));
    const uint32_t Cout= static_cast<uint32_t>(wShape->GetOriginShape().GetDim(1));
    const uint32_t kD = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(2));
    const uint32_t kH = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(3));
    const uint32_t kW = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(4));

    if (CinW != Cin) {
        return ge::GRAPH_FAILED;
    }

    // stride=(1,1,1), padding=(0,0,0), dilation=(1,1,1), output_padding=(0,0,0)
    const uint32_t OD = D + kD - 1;
    const uint32_t OH = H + kH - 1;
    const uint32_t OW = W + kW - 1;

    // tileW from UB budget: bytes = 8 * tileW
    uint32_t maxTile = UB_BUDGET_BYTES / 8;  // elements
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileW = maxTile;
    if (OW < tileW) {
        const uint32_t aligned = AlignDown(OW, ALIGN_ELEMS);
        tileW = (aligned > 0) ? aligned : OW;
    }

    const uint64_t totalLines = static_cast<uint64_t>(N) * Cout * OD * OH;
    uint32_t blockDim = CeilDiv(totalLines, static_cast<uint64_t>(1));
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_Cin(Cin);
    tiling.set_Cout(Cout);
    tiling.set_D(D);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_OD(OD);
    tiling.set_OH(OH);
    tiling.set_OW(OW);
    tiling.set_tileW(tileW);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

